// Star-tiered random caption selector
// Picks from 5-star pool first; falls back to 4-star if empty
// Skips rows already marked Caption_Used = TRUE
//
// NOTE: The 'Rating' column has a trailing space in the sheet header.
// Match it exactly as 'Rating ' (with space).

const rows = $input.all();

const eligible = rows.filter(row => {
  const rating = parseInt((row.json['Rating '] || '0').toString().trim());
  const used = (row.json['Caption_Used'] || '').toString().trim().toUpperCase();
  return rating >= 4 && used !== 'TRUE';
});

if (eligible.length === 0) {
  throw new Error(
    'No eligible captions found. ' +
    'Make sure approved_content has rows with Rating 4 or 5 ' +
    'and Caption_Used column blank or FALSE.'
  );
}

const fiveStars = eligible.filter(
  r => parseInt((r.json['Rating '] || '0').toString().trim()) === 5
);
const fourStars = eligible.filter(
  r => parseInt((r.json['Rating '] || '0').toString().trim()) === 4
);

// 5-star pool first; fall back to 4-star
const pool = fiveStars.length > 0 ? fiveStars : fourStars;

// Random pick within the chosen pool
const picked = pool[Math.floor(Math.random() * pool.length)];

// Preserve row number (1-indexed, +1 for header) for downstream update
const rowIndex = rows.indexOf(picked) + 2;

return [{
  json: {
    ...picked.json,
    _row_index: rowIndex,
    _pool_size: pool.length,
    _pool_tier: fiveStars.length > 0 ? '5-star' : '4-star'
  }
}];

