const raw = $input.first().json.output ?? $input.first().json.text ?? '';

let prompt;
try {
  const parsed = JSON.parse(raw);
  prompt = parsed.prompt ?? raw;
} catch (e) {
  // Agent 1 returned plain text instead of JSON
  prompt = raw;
}

if (!prompt) throw new Error('Parse Prompt: no prompt found in Agent 1 output: ' + raw);

return [{ json: { prompt } }];

const result = $input.first().json;
const resultJson = JSON.parse(result.data.resultJson);
const imageUrl = resultJson.resultUrls[0];

if (!imageUrl) throw new Error('No image URL: ' + JSON.stringify(result));

return [{ json: { imageUrl } }];

